import React, { useState, useEffect } from 'react';
import { Plus, Box, Trash2, Edit2, X } from 'lucide-react';
import { Product } from '../types';

interface Props {
  products: Product[];
  onAdd: (p: Product) => void;
  onUpdate: (p: Product) => void;
  onDelete: (id: string) => void;
}

const ProductManager: React.FC<Props> = ({ products, onAdd, onUpdate, onDelete }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [formData, setFormData] = useState({ 
    name: '', 
    description: '', 
    priceJakarta: 0, 
    priceLuarKota: 0 
  });

  useEffect(() => {
    if (editingProduct) {
      setFormData({
        name: editingProduct.name || '',
        description: editingProduct.description || '',
        priceJakarta: editingProduct.priceJakarta || 0,
        priceLuarKota: editingProduct.priceLuarKota || 0
      });
      setIsFormOpen(true);
    }
  }, [editingProduct]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      onUpdate({ ...editingProduct, ...formData });
    } else {
      onAdd({ id: Math.random().toString(36).substr(2, 9), ...formData });
    }
    resetForm();
  };

  const resetForm = () => {
    setFormData({ name: '', description: '', priceJakarta: 0, priceLuarKota: 0 });
    setEditingProduct(null);
    setIsFormOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Manajemen Barang</h2>
          <p className="text-slate-500 text-sm">Atur katalog produk dan harga jual</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="bg-indigo-600 text-white px-4 py-2.5 rounded-xl font-bold text-sm flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={18} /> Tambah Barang
        </button>
      </div>

      {isFormOpen && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 grid grid-cols-1 md:grid-cols-2 gap-4 animate-in slide-in-from-top-2 duration-300">
          <div className="md:col-span-2 flex justify-between items-center border-b pb-2 mb-2">
            <h3 className="font-bold text-slate-800">{editingProduct ? 'Edit Data Produk' : 'Input Produk Baru'}</h3>
            <button type="button" onClick={resetForm} className="text-slate-400 hover:text-slate-600 p-1"><X size={20}/></button>
          </div>
          <div className="space-y-1 md:col-span-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Nama Barang</label>
            <input required className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          </div>

          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Harga Jual Jakarta</label>
            <div className="relative">
               <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-black">Rp</span>
               <input required type="number" className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold" value={formData.priceJakarta} onChange={e => setFormData({...formData, priceJakarta: Number(e.target.value)})} />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Harga Jual Luar Kota</label>
            <div className="relative">
               <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-black">Rp</span>
               <input required type="number" className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold" value={formData.priceLuarKota} onChange={e => setFormData({...formData, priceLuarKota: Number(e.target.value)})} />
            </div>
          </div>
          <div className="space-y-1 md:col-span-2">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Keterangan Produk</label>
            <textarea rows={2} className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none resize-none text-sm font-medium" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
          </div>
          <div className="md:col-span-2 flex gap-2 pt-2">
            <button type="submit" className="bg-slate-800 text-white px-6 py-2 rounded-lg font-bold text-sm hover:bg-slate-900 transition-colors">
              {editingProduct ? 'Simpan Perubahan' : 'Simpan Produk'}
            </button>
            <button type="button" onClick={resetForm} className="bg-slate-100 text-slate-600 px-6 py-2 rounded-lg font-bold text-sm">Batal</button>
          </div>
        </form>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {products.map(p => (
          <div key={p.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative group overflow-hidden transition-all hover:shadow-md">
            <div className="flex justify-between items-start mb-4">
              <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                <Box size={24} className="text-indigo-500" />
              </div>
              <div className="flex gap-1">
                <button 
                  type="button"
                  onClick={(e) => { e.preventDefault(); e.stopPropagation(); setEditingProduct(p); }}
                  className="p-1.5 text-slate-400 hover:text-amber-500 transition-colors"
                  title="Edit Barang"
                >
                  <Edit2 size={16} />
                </button>
                <button 
                  type="button"
                  onClick={(e) => { e.preventDefault(); e.stopPropagation(); onDelete(p.id); }}
                  className="p-1.5 text-rose-400 hover:text-rose-600 transition-colors"
                  title="Hapus Barang"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
            <h4 className="font-bold text-slate-800 text-lg mb-1">{p.name}</h4>
            <p className="text-xs text-slate-400 mb-4 line-clamp-2 min-h-[32px] font-medium leading-relaxed">{p.description || 'Tidak ada keterangan produk.'}</p>

            <div className="space-y-3 pt-4 border-t border-slate-50">
               <div className="flex justify-between items-center">
                 <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Jual Jakarta</span>
                 <span className="text-sm font-bold text-slate-700">Rp {p.priceJakarta.toLocaleString()}</span>
               </div>
               <div className="flex justify-between items-center">
                 <span className="text-[10px] font-black text-amber-500/60 uppercase tracking-widest">Jual Luar Kota</span>
                 <span className="text-sm font-bold text-indigo-600">Rp {p.priceLuarKota.toLocaleString()}</span>
               </div>
            </div>
          </div>
        ))}
        {products.length === 0 && (
          <div className="col-span-full py-20 text-center text-slate-400 bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <Box size={40} className="mx-auto mb-3 opacity-10" />
            <p className="text-sm font-bold uppercase tracking-widest opacity-50">Katalog barang masih kosong.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProductManager;

import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Trophy, Search, FileText, Image as ImageIcon, 
  ListOrdered, PieChart, ShoppingBag
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month') => {
    const end = new Date();
    const start = new Date();
    if (type === 'today') start.setHours(0,0,0,0);
    else if (type === 'week') start.setDate(end.getDate() - 7);
    else if (type === 'month') start.setMonth(end.getMonth() - 1);
    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);
      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }
      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || order.customerName.toLowerCase().includes(searchLower) || order.invoiceNumber.toLowerCase().includes(searchLower);
      return matchesTime && matchesCustomer && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, searchTerm]);

  const stats = useMemo(() => {
    let revenue = 0;
    filteredOrders.forEach(o => {
      revenue += (o.subtotal || 0);
    });
    return {
      totalRevenue: revenue,
      orderCount: filteredOrders.length
    };
  }, [filteredOrders]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0 };
        salesMap[item.productId].qty += item.quantity;
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f1f5f9' });
    const link = document.createElement('a');
    link.download = `Laporan_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f1f5f9' });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 pb-20 max-w-6xl mx-auto">
      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div>
             <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Filter Laporan</h3>
           </div>
           <div className="flex gap-2 w-full md:w-auto">
              <button onClick={handleDownloadJPG} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-slate-100 rounded-xl text-slate-600 text-[10px] font-black hover:bg-slate-200 transition-all"><ImageIcon size={14} /> JPG</button>
              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"><FileText size={14} /> PDF</button>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end border-t border-slate-100 pt-6">
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Rentang Cepat</label>
            <div className="flex gap-1">
              {['today', 'week', 'month'].map(t => (
                <button key={t} onClick={() => setPreset(t as any)} className="flex-1 px-2 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[9px] font-bold text-slate-600 uppercase">
                  {t === 'today' ? 'Hari ini' : t === 'week' ? '7 Hari' : '30 Hari'}
                </button>
              ))}
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pelanggan</label>
            <select className="w-full px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={filterCustomer} onChange={e => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-2 md:col-span-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pencarian</label>
            <div className="relative">
              <input type="text" placeholder="Cari invoice atau nama..." className="w-full pl-8 pr-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-2 text-slate-300" size={12} />
            </div>
          </div>
        </div>
      </div>

      <div ref={reportRef} className="bg-slate-100 p-6 md:p-10 rounded-[2.5rem] space-y-6 text-slate-900 border border-slate-200 shadow-inner">
        <div className="bg-white p-8 rounded-[2rem] shadow-sm flex flex-col md:flex-row justify-between items-center gap-6 border border-slate-100">
           <div>
              <h1 className="text-xl font-black uppercase text-slate-900">Laporan Penjualan</h1>
              <p className="text-indigo-500 text-[9px] font-black uppercase tracking-[0.3em] mt-1">Buku PO Online System</p>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
             <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-500">
                  <PieChart size={18}/>
                </div>
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Total Omzet</p>
                  <h2 className="text-lg font-black text-slate-900">Rp {stats.totalRevenue.toLocaleString()}</h2>
                </div>
             </div>

             <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 rounded-xl bg-emerald-50 flex items-center justify-center text-emerald-500">
                  <ShoppingBag size={18}/>
                </div>
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Total Pesanan</p>
                  <h2 className="text-lg font-black text-slate-900">{stats.orderCount} Transaksi</h2>
                </div>
             </div>
        </div>

        <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm">
           <div className="flex items-center gap-2 mb-6">
             <Trophy size={16} className="text-amber-500"/>
             <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Peringkat Penjualan</h3>
           </div>
