const ProductManager: React.FC<Props> = ({ products, onAdd, onUpdate, onDelete }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [formData, setFormData] = useState({ 
    name: '', 
    description: '', 
    costPrice: 0,
    priceJakarta: 0, 
    priceLuarKota: 0 
  });

  useEffect(() => {
    if (editingProduct) {
      setFormData({
        name: editingProduct.name || '',
        description: editingProduct.description || '',
        costPrice: editingProduct.costPrice || 0,
        priceJakarta: editingProduct.priceJakarta || 0,
        priceLuarKota: editingProduct.priceLuarKota || 0
      });
      setIsFormOpen(true);
    }
  }, [editingProduct]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingProduct) {
      onUpdate({ ...editingProduct, ...formData });
    } else {
      onAdd({ id: Math.random().toString(36).substr(2, 9), ...formData });
    }
    resetForm();
  };

  const resetForm = () => {
    setFormData({ name: '', description: '', costPrice: 0, priceJakarta: 0, priceLuarKota: 0 });
    setEditingProduct(null);
    setIsFormOpen(false);
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Manajemen Barang</h2>
          <p className="text-slate-500 text-sm">Atur katalog produk, harga modal, dan harga jual</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="bg-indigo-600 text-white px-4 py-2.5 rounded-xl font-bold text-sm flex items-center gap-2 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={18} /> Tambah Barang
        </button>
      </div>

      {isFormOpen && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-xl border border-slate-100 grid grid-cols-1 md:grid-cols-3 gap-4 animate-in slide-in-from-top-2 duration-300">
          <div className="md:col-span-3 flex justify-between items-center border-b pb-2 mb-2">
            <h3 className="font-bold text-slate-800">{editingProduct ? 'Edit Data Produk' : 'Input Produk Baru'}</h3>
            <button type="button" onClick={resetForm} className="text-slate-400 hover:text-slate-600 p-1"><X size={20}/></button>
          </div>
          <div className="space-y-1 md:col-span-3">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Nama Barang</label>
            <input required className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
          </div>

          <div className="space-y-1">
            <label className="text-xs font-bold text-rose-500 uppercase tracking-wider flex items-center gap-1"><Wallet size={12}/> Harga Ambil (Modal)</label>
            <div className="relative">
               <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-black">Rp</span>
               <input required type="number" className="w-full pl-10 pr-4 py-2 rounded-lg border border-rose-100 bg-rose-50/30 focus:ring-2 focus:ring-rose-500 outline-none font-bold" value={formData.costPrice} onChange={e => setFormData({...formData, costPrice: Number(e.target.value)})} />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Harga Jual Jakarta</label>
            <div className="relative">
               <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-black">Rp</span>
               <input required type="number" className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold" value={formData.priceJakarta} onChange={e => setFormData({...formData, priceJakarta: Number(e.target.value)})} />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Harga Jual Luar Kota</label>
            <div className="relative">
               <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-black">Rp</span>
               <input required type="number" className="w-full pl-10 pr-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none font-bold" value={formData.priceLuarKota} onChange={e => setFormData({...formData, priceLuarKota: Number(e.target.value)})} />
            </div>
          </div>

          <div className="space-y-1 md:col-span-3">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Keterangan Produk</label>
            <textarea rows={2} className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none resize-none text-sm font-medium" value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
          </div>
          <div className="md:col-span-3 flex gap-2 pt-2">
            <button type="submit" className="bg-slate-800 text-white px-6 py-2 rounded-lg font-bold text-sm hover:bg-slate-900 transition-colors">
              {editingProduct ? 'Simpan Perubahan' : 'Simpan Produk'}
            </button>
            <button type="button" onClick={resetForm} className="bg-slate-100 text-slate-600 px-6 py-2 rounded-lg font-bold text-sm">Batal</button>
          </div>
        </form>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {products.map(p => (
          <div key={p.id} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative group overflow-hidden transition-all hover:shadow-md">
            <div className="flex justify-between items-start mb-4">
              <div className="bg-slate-50 p-3 rounded-xl border border-slate-100">
                <Box size={24} className="text-indigo-500" />
              </div>
              <div className="flex gap-1">
                <button 
                  type="button"
                  onClick={(e) => { e.preventDefault(); e.stopPropagation(); setEditingProduct(p); }}
                  className="p-1.5 text-slate-400 hover:text-amber-500 transition-colors"
                  title="Edit Barang"
                >
                  <Edit2 size={16} />
                </button>
                <button 
                  type="button"
                  onClick={(e) => { e.preventDefault(); e.stopPropagation(); onDelete(p.id); }}
                  className="p-1.5 text-rose-400 hover:text-rose-600 transition-colors"
                  title="Hapus Barang"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            </div>
            <h4 className="font-bold text-slate-800 text-lg mb-1">{p.name}</h4>
            <p className="text-xs text-slate-400 mb-4 line-clamp-2 min-h-[32px] font-medium leading-relaxed">{p.description || 'Tidak ada keterangan produk.'}</p>

            <div className="space-y-3 pt-4 border-t border-slate-50">
               <div className="flex justify-between items-center px-3 py-1.5 bg-rose-50 rounded-lg">
                 <span className="text-[10px] font-black text-rose-400 uppercase tracking-widest">Modal (Ambil)</span>
                 <span className="text-sm font-black text-rose-600">Rp {(p.costPrice || 0).toLocaleString()}</span>
               </div>
               <div className="flex justify-between items-center px-3">
                 <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Jual Jakarta</span>
                 <span className="text-sm font-bold text-slate-700">Rp {p.priceJakarta.toLocaleString()}</span>
               </div>
               <div className="flex justify-between items-center px-3">
                 <span className="text-[10px] font-black text-amber-500/60 uppercase tracking-widest">Jual Luar Kota</span>
                 <span className="text-sm font-bold text-indigo-600">Rp {p.priceLuarKota.toLocaleString()}</span>
               </div>
            </div>
          </div>
        ))}
        {products.length === 0 && (
          <div className="col-span-full py-20 text-center text-slate-400 bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <Box size={40} className="mx-auto mb-3 opacity-10" />
            <p className="text-sm font-bold uppercase tracking-widest opacity-50">Katalog barang masih kosong.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default ProductManager;

import React, { useState, useMemo, useEffect } from 'react';
import { 
  Plus, ShoppingCart, Trash2, Eye, User, 
  Package, Check, CreditCard, Edit3, X, Calendar, Loader2, AlertCircle, Edit2
} from 'lucide-react';
import { AppState, Order, OrderItem, Product, OrderStatus, LocationType, PaymentRecord } from '../types';

interface Props {
  state: AppState;
  onAddOrder: (o: Order) => Promise<any>;
  onUpdateOrder: (o: Order) => Promise<any>;
  onDeleteOrder: (id: string) => void;
  onViewInvoice: (o: Order) => void;
}

const OrderManager: React.FC<Props> = ({ state, onAddOrder, onUpdateOrder, onDeleteOrder, onViewInvoice }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingOrder, setEditingOrder] = useState<Order | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);

  const [selectedCustomerId, setSelectedCustomerId] = useState('');
  const [orderItems, setOrderItems] = useState<{ productId: string, qty: number }[]>([]);
  const [payments, setPayments] = useState<PaymentRecord[]>([]);
  const [notes, setNotes] = useState('');
  const [orderDate, setOrderDate] = useState(new Date().toISOString().split('T')[0]);

  const [newPaymentAmount, setNewPaymentAmount] = useState<number>(0);
  const [newPaymentNote, setNewPaymentNote] = useState<string>('');
  const [showPaymentInput, setShowPaymentInput] = useState(false);
  const [editingPaymentId, setEditingPaymentId] = useState<string | null>(null);

  // Sync state when editing
  useEffect(() => {
    if (editingOrder) {
      setSelectedCustomerId(editingOrder.customerId || '');
      setOrderItems(editingOrder.items ? editingOrder.items.map(i => ({ productId: i.productId, qty: i.quantity })) : []);
      setPayments(editingOrder.payments || []);
      setNotes(editingOrder.notes || '');
      setOrderDate(new Date(editingOrder.orderDate).toISOString().split('T')[0]);
      setIsFormOpen(true);
      setFormError(null);
    }
  }, [editingOrder]);

  const selectedCustomer = useMemo(() => 
    state.customers.find(c => c.id === selectedCustomerId), 
    [state.customers, selectedCustomerId]
  );

  const calculateItemPrice = (product: Product, location: LocationType) => {
    return location === LocationType.LUAR_KOTA ? (Number(product.priceLuarKota) || 0) : (Number(product.priceJakarta) || 0);
  };

  const calculatedSubtotal = useMemo(() => {
    if (!selectedCustomer) return 0;
    return orderItems.reduce((sum, item) => {
      const product = state.products.find(p => p.id === item.productId);
      if (!product) return sum;
      return sum + (calculateItemPrice(product, selectedCustomer.type) * Number(item.qty));
    }, 0);
  }, [orderItems, selectedCustomer, state.products]);

  const currentTotalPaid = useMemo(() => {
    return payments.reduce((sum, p) => sum + (Number(p.amount) || 0), 0);
  }, [payments]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError(null);

    if (isSubmitting) return;

    if (!selectedCustomerId || !selectedCustomer) {
      setFormError("Silakan pilih pelanggan terlebih dahulu.");
      return;
    }
    if (orderItems.length === 0) {
      setFormError("Tambahkan minimal satu barang ke dalam pesanan.");
      return;
    }

    setIsSubmitting(true);
    try {
      const items: OrderItem[] = orderItems.map(oi => {
        const p = state.products.find(product => product.id === oi.productId);
        if (!p) throw new Error(`Produk dengan ID ${oi.productId} tidak ditemukan`);

        const price = calculateItemPrice(p, selectedCustomer.type);
        return {
          id: Math.random().toString(36).substr(2, 9),
          productId: p.id,
          name: p.name,
          quantity: Number(oi.qty),
          unitPrice: Number(price),
          costPrice: Number(p.costPrice || 0) // Menangkap harga modal saat transaksi dibuat
        };
      });

      const finalSubtotal = Number(calculatedSubtotal);
      const finalPaid = Number(currentTotalPaid);
      const finalRemaining = Math.max(0, finalSubtotal - finalPaid);

      const orderData: Order = {
        id: editingOrder ? editingOrder.id : `ord_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`,
        invoiceNumber: editingOrder ? editingOrder.invoiceNumber : `INV-${Date.now().toString().slice(-6)}`,
        customerId: selectedCustomerId,
        customerName: selectedCustomer.name,
        customerEmail: selectedCustomer.email || '',
        customerType: selectedCustomer.type,
        customerAddress: selectedCustomer.address || '',
        orderDate: new Date(orderDate).toISOString(),
        status: finalRemaining <= 0 ? OrderStatus.PAID : OrderStatus.PENDING,
        items: items,
        subtotal: finalSubtotal,
        downPayment: finalPaid,
        payments: payments,
        total: finalRemaining,
        notes: notes.trim()
      };

      if (editingOrder) {
        await onUpdateOrder(orderData);
      } else {
        await onAddOrder(orderData);
      }

      resetForm();
    } catch (err: any) {
      console.error("Submit order logic error:", err);
      setFormError(err.message || "Gagal menyimpan data.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const addOrUpdatePayment = () => {
    const amount = Number(newPaymentAmount);
    if (isNaN(amount) || amount <= 0) {
      alert("Masukkan nominal pembayaran yang valid");
      return;
    }

    if (editingPaymentId) {
      // Update existing payment
      setPayments(payments.map(p => p.id === editingPaymentId ? {
        ...p,
        amount: amount,
        note: newPaymentNote.trim() || p.note
      } : p));
      setEditingPaymentId(null);
    } else {
      // Add new payment
      const newRecord: PaymentRecord = {
        id: Math.random().toString(36).substr(2, 9),
        amount: amount,
        date: new Date().toISOString(),
        note: newPaymentNote.trim() || (payments.length === 0 ? 'DP Utama' : `DP Tambahan ke-${payments.length + 1}`)
      };
      setPayments([...payments, newRecord]);
    }

    setNewPaymentAmount(0);
    setNewPaymentNote('');
    setShowPaymentInput(false);
  };

  const removePayment = (id: string) => {
    if (window.confirm('Hapus catatan pembayaran ini?')) {
      setPayments(payments.filter(p => p.id !== id));
      if (editingPaymentId === id) {
        setEditingPaymentId(null);
        setNewPaymentAmount(0);
        setNewPaymentNote('');
        setShowPaymentInput(false);
      }
    }
  };

  const startEditPayment = (p: PaymentRecord) => {
    setEditingPaymentId(p.id);
    setNewPaymentAmount(p.amount);
    setNewPaymentNote(p.note || '');
    setShowPaymentInput(true);
  };

  const resetForm = () => {
    setIsFormOpen(false);
    setEditingOrder(null);
    setSelectedCustomerId('');
    setOrderItems([]);
    setPayments([]);
    setNotes('');
    setOrderDate(new Date().toISOString().split('T')[0]);
    setShowPaymentInput(false);
    setEditingPaymentId(null);
    setNewPaymentAmount(0);
    setNewPaymentNote('');
    setIsSubmitting(false);
    setFormError(null);
  };

  return (
    <div className="space-y-6 pb-20 md:pb-0">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-xl md:text-2xl font-bold text-slate-800 tracking-tight">Daftar Transaksi</h2>
          <p className="text-slate-500 text-xs md:text-sm font-medium">Buat invoice dan kelola piutang pelanggan</p>
        </div>
        <button 
          onClick={() => { resetForm(); setIsFormOpen(true); }}
          className="w-full sm:w-auto bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 active:scale-95"
        >
          <Plus size={18} /> Buat Order
        </button>
      </div>

      {isFormOpen && (
        <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-6 md:p-10 animate-in slide-in-from-top-4 duration-500">
           <div className="flex justify-between items-center mb-10">
             <div>
               <h3 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">{editingOrder ? 'Koreksi Pesanan' : 'Input Pesanan Baru'}</h3>
               <p className="text-xs text-slate-400 font-bold uppercase tracking-wider mt-1">{editingOrder ? editingOrder.invoiceNumber : 'Invoice Otomatis'}</p>
             </div>
             <button onClick={resetForm} disabled={isSubmitting} className="p-3 hover:bg-slate-50 rounded-2xl text-slate-400 transition-colors disabled:opacity-30"><X size={24}/></button>
           </div>

           {formError && (
             <div className="mb-8 p-4 bg-rose-50 border border-rose-100 rounded-2xl flex items-center gap-3 text-rose-600 animate-in fade-in zoom-in-95">
                <AlertCircle size={20} />
                <p className="text-xs font-black uppercase tracking-tight">{formError}</p>
             </div>
           )}

           <form onSubmit={handleSubmit} className="space-y-10">
             <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                <div className="space-y-8">
                  <div className="space-y-4">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <Calendar size={14} className="text-indigo-500"/> 1. Waktu Transaksi
                    </h3>
                    <input 
                      required
                      type="date"
                      className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:ring-4 focus:ring-indigo-500/10 bg-slate-50 outline-none font-bold text-sm transition-all"
                      value={orderDate}
                      onChange={e => setOrderDate(e.target.value)}
                    />
                  </div>

                  <div className="space-y-4">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <User size={14} className="text-indigo-500"/> 2. Identitas Pelanggan
                    </h3>
                    <select 
                      required
                      className="w-full px-5 py-4 rounded-2xl border border-slate-200 focus:ring-4 focus:ring-indigo-500/10 bg-slate-50 outline-none font-bold text-sm appearance-none cursor-pointer transition-all"
                      value={selectedCustomerId}
                      onChange={e => setSelectedCustomerId(e.target.value)}
                    >
                      <option value="">-- Cari Nama Pelanggan --</option>
                      {state.customers.map(c => (
                        <option key={c.id} value={c.id}>{c.name} ({c.type})</option>
                      ))}
                    </select>
                  </div>
                </div>

                <div className="space-y-4">
                   <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                    <Package size={14} className="text-indigo-500"/> 3. Detail Barang
                  </h3>
                  <div className="space-y-3 max-h-[350px] overflow-y-auto pr-2 no-scrollbar border-2 border-dashed border-slate-100 p-4 rounded-3xl bg-slate-50/30">
                    {state.products.map(p => {
                      const existing = orderItems.find(oi => oi.productId === p.id);
                      return (
                        <div key={p.id} className={`flex items-center justify-between p-4 rounded-2xl border transition-all ${
                          existing ? 'bg-white border-indigo-200 shadow-xl shadow-indigo-500/5' : 'bg-white/50 border-slate-100'
                        }`}>
                           <div className="min-w-0 flex-1 pr-4">
                             <p className="text-xs font-black text-slate-800 truncate">{p.name}</p>
                             <div className="flex flex-col mt-1">
                               <p className="text-[9px] text-slate-400 font-black uppercase tracking-wider">
                                 Jual: Rp {(selectedCustomer ? calculateItemPrice(p, selectedCustomer.type) : Number(p.priceJakarta)).toLocaleString()}
                               </p>
                               <p className="text-[8px] text-rose-400 font-bold uppercase">
                                 Modal: Rp {(p.costPrice || 0).toLocaleString()}
                               </p>
                             </div>
                           </div>
                           <div className="flex items-center gap-3 shrink-0">
                             {existing && (
                               <div className="flex items-center bg-indigo-50 rounded-xl px-2">
                                 <span className="text-[8px] font-black text-indigo-400 uppercase mr-1">Qty</span>
                                 <input 
                                   type="number"
                                   min="1"
                                   className="w-10 py-2 border-none text-xs font-black text-center outline-none bg-transparent text-indigo-700"
                                   value={existing.qty}
                                   onChange={e => {
                                     const val = Math.max(1, parseInt(e.target.value) || 1);
                                     setOrderItems(orderItems.map(i => i.productId === p.id ? { ...i, qty: val } : i));
                                   }}
                                 />
                               </div>
                             )}
                             <button 
                               type="button"
                               onClick={() => {
                                 if (!existing) {
                                   setOrderItems([...orderItems, { productId: p.id, qty: 1 }]);
                                 } else {
                                   setOrderItems(orderItems.filter(i => i.productId !== p.id));
                                 }
                               }}
                               className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${
                                 existing ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white text-slate-300 border border-slate-200 hover:text-indigo-600'
                               }`}
                             >
                               {existing ? <Check size={18} /> : <Plus size={18} />}
                             </button>
                           </div>
                        </div>
                      )
                    })}
                  </div>
                </div>
             </div>

             <div className="grid grid-cols-1 md:grid-cols-2 gap-10 pt-10 border-t border-slate-100">
                <div className="space-y-6">
                  <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                      <CreditCard size={14} className="text-indigo-500"/> 4. Pembayaran / DP
                    </h3>
                    <button 
                      type="button" 
                      onClick={() => {
                        if (editingPaymentId) {
                          setEditingPaymentId(null);
                          setNewPaymentAmount(0);
                          setNewPaymentNote('');
                        }
                        setShowPaymentInput(!showPaymentInput);
                      }}
                      className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-xl border border-indigo-100 hover:bg-indigo-100 transition-all active:scale-95"
                    >
                      {showPaymentInput ? 'Batal' : '+ Tambah Bayar'}
                    </button>
                  </div>

                  {showPaymentInput && (
                    <div className="bg-slate-900 p-6 rounded-3xl space-y-4 shadow-2xl animate-in fade-in zoom-in-95 duration-300">
                      <div className="grid grid-cols-1 gap-4">
                        <div className="space-y-1">
                          <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Nominal Pembayaran</label>
                          <div className="relative">
                             <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 text-[10px] font-black">RP</span>
                             <input 
                              type="number"
                              placeholder="0"
                              className="w-full pl-10 pr-5 py-3 rounded-2xl bg-white/10 border border-white/10 text-white text-sm font-black outline-none focus:border-indigo-500 transition-all"
                              value={newPaymentAmount || ''}
                              onChange={e => setNewPaymentAmount(Number(e.target.value))}
                            />
                          </div>
                        </div>
                        <div className="space-y-1">
                           <label className="text-[9px] font-black text-slate-500 uppercase ml-1">Keterangan</label>
                           <input 
                            type="text"
                            placeholder="Catatan pembayaran..."
                            className="w-full px-5 py-3 rounded-2xl bg-white/10 border border-white/10 text-white text-sm font-medium outline-none focus:border-indigo-500 transition-all"
