import React, { useMemo, useState, useRef } from 'react';
import { AppState } from '../types';
import { 
  Trophy, Search, FileText, Image as ImageIcon, 
  ListOrdered, PieChart, ShoppingBag, TrendingUp, Wallet
} from 'lucide-react';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface ReportsProps {
  state: AppState;
}

const Reports: React.FC<ReportsProps> = ({ state }) => {
  const reportRef = useRef<HTMLDivElement>(null);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [filterCustomer, setFilterCustomer] = useState('all');
  const [searchTerm, setSearchTerm] = useState('');

  const formatDate = (date: Date) => {
    const d = new Date(date);
    d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
    return d.toISOString().split('T')[0];
  };

  const setPreset = (type: 'today' | 'week' | 'month') => {
    const end = new Date();
    const start = new Date();
    if (type === 'today') start.setHours(0,0,0,0);
    else if (type === 'week') start.setDate(end.getDate() - 7);
    else if (type === 'month') start.setMonth(end.getMonth() - 1);
    setStartDate(formatDate(start));
    setEndDate(formatDate(end));
  };

  const filteredOrders = useMemo(() => {
    return state.orders.filter(order => {
      const orderDate = new Date(order.orderDate);
      orderDate.setHours(0, 0, 0, 0);
      let matchesTime = true;
      if (startDate) {
        const start = new Date(startDate);
        start.setHours(0, 0, 0, 0);
        matchesTime = matchesTime && orderDate >= start;
      }
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        matchesTime = matchesTime && orderDate <= end;
      }
      const matchesCustomer = filterCustomer === 'all' || order.customerId === filterCustomer;
      const searchLower = searchTerm.toLowerCase().trim();
      const matchesSearch = searchTerm === '' || order.customerName.toLowerCase().includes(searchLower) || order.invoiceNumber.toLowerCase().includes(searchLower);
      return matchesTime && matchesCustomer && matchesSearch;
    });
  }, [state.orders, startDate, endDate, filterCustomer, searchTerm]);

  const stats = useMemo(() => {
    let revenue = 0;
    let totalCost = 0;
    filteredOrders.forEach(o => {
      revenue += (o.subtotal || 0);
      o.items.forEach(item => {
        totalCost += (Number(item.costPrice || 0) * item.quantity);
      });
    });
    return {
      totalRevenue: revenue,
      totalCost: totalCost,
      totalProfit: revenue - totalCost,
      orderCount: filteredOrders.length
    };
  }, [filteredOrders]);

  const productSales = useMemo(() => {
    const salesMap: Record<string, { name: string, qty: number }> = {};
    filteredOrders.forEach(order => {
      order.items.forEach(item => {
        if (!salesMap[item.productId]) salesMap[item.productId] = { name: item.name, qty: 0 };
        salesMap[item.productId].qty += item.quantity;
      });
    });
    return Object.values(salesMap).sort((a, b) => b.qty - a.qty);
  }, [filteredOrders]);

  const handleDownloadJPG = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f1f5f9' });
    const link = document.createElement('a');
    link.download = `Laporan_${new Date().getTime()}.jpg`;
    link.href = canvas.toDataURL('image/jpeg', 0.9);
    link.click();
  };

  const handleDownloadPDF = async () => {
    if (!reportRef.current) return;
    const canvas = await html2canvas(reportRef.current, { scale: 2, backgroundColor: '#f1f5f9' });
    const imgData = canvas.toDataURL('image/png');
    const pdf = new jsPDF('p', 'mm', 'a4');
    const pdfWidth = pdf.internal.pageSize.getWidth();
    const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
    pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
    pdf.save(`Laporan_${new Date().getTime()}.pdf`);
  };

  return (
    <div className="space-y-6 pb-20 max-w-6xl mx-auto">
      <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm space-y-6">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
           <div>
             <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">Filter Laporan</h3>
           </div>
           <div className="flex gap-2 w-full md:w-auto">
              <button onClick={handleDownloadJPG} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-slate-100 rounded-xl text-slate-600 text-[10px] font-black hover:bg-slate-200 transition-all"><ImageIcon size={14} /> JPG</button>
              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"><FileText size={14} /> PDF</button>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end border-t border-slate-100 pt-6">
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Rentang Cepat</label>
            <div className="flex gap-1">
              {['today', 'week', 'month'].map(t => (
                <button key={t} onClick={() => setPreset(t as any)} className="flex-1 px-2 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[9px] font-bold text-slate-600 uppercase">
                  {t === 'today' ? 'Hari ini' : t === 'week' ? '7 Hari' : '30 Hari'}
                </button>
              ))}
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pelanggan</label>
            <select className="w-full px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={filterCustomer} onChange={e => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-2 md:col-span-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pencarian</label>
            <div className="relative">
              <input type="text" placeholder="Cari invoice atau nama..." className="w-full pl-8 pr-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-2 text-slate-300" size={12} />
            </div>
          </div>
        </div>
      </div>

      <div ref={reportRef} className="bg-slate-100 p-6 md:p-10 rounded-[2.5rem] space-y-6 text-slate-900 border border-slate-200 shadow-inner">
        <div className="bg-white p-8 rounded-[2rem] shadow-sm flex flex-col md:flex-row justify-between items-center gap-6 border border-slate-100">
           <div>
              <h1 className="text-xl font-black uppercase text-slate-900">Laporan Penjualan</h1>
              <p className="text-indigo-500 text-[9px] font-black uppercase tracking-[0.3em] mt-1">Buku PO Online System</p>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
             <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 rounded-xl bg-indigo-50 flex items-center justify-center text-indigo-500">
                  <PieChart size={18}/>
                </div>
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Total Omzet</p>
                  <h2 className="text-lg font-black text-slate-900">Rp {stats.totalRevenue.toLocaleString()}</h2>
                </div>
             </div>

             <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm flex items-center gap-4">
                <div className="w-10 h-10 rounded-xl bg-rose-50 flex items-center justify-center text-rose-500">
                  <Wallet size={18}/>
                </div>
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Total Modal</p>
                  <h2 className="text-lg font-black text-slate-900 text-rose-600">Rp {stats.totalCost.toLocaleString()}</h2>
                </div>
             </div>

             <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm flex items-center gap-4 relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-5 group-hover:scale-110 transition-transform"><TrendingUp size={60} /></div>
                <div className="w-10 h-10 rounded-xl bg-emerald-500 flex items-center justify-center text-white shadow-lg shadow-emerald-200">
                  <TrendingUp size={18}/>
                </div>
                <div>
                  <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5">Estimasi Keuntungan</p>
                  <h2 className="text-xl font-black text-emerald-600">Rp {stats.totalProfit.toLocaleString()}</h2>
                </div>
             </div>
        </div>

        <div className="bg-white p-6 rounded-[1.5rem] border border-slate-200 shadow-sm">
           <div className="flex items-center gap-2 mb-6">
             <Trophy size={16} className="text-amber-500"/>
             <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Peringkat Penjualan</h3>
           </div>
           <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
              {productSales.slice(0, 5).map((p, i) => (
                <div key={i} className="p-3 rounded-xl border border-slate-100 bg-slate-50/50 text-center">
                   <p className="text-[11px] font-bold text-slate-800 truncate mb-1">{p.name}</p>
                   <p className="text-[9px] font-black text-slate-400 uppercase tracking-tighter">{p.qty} UNIT</p>
                </div>
              ))}
           </div>
        </div>

        <div className="bg-white rounded-[1.5rem] border border-slate-200 shadow-sm overflow-hidden">
          <div className="px-6 py-4 border-b border-slate-100 flex items-center justify-between bg-slate-50/50">
            <div className="flex items-center gap-2">
              <ListOrdered size={16} className="text-indigo-500" />
              <h3 className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Rincian Transaksi & Profit</h3>
            </div>
          </div>
          <table className="w-full text-left">
            <thead>
              <tr className="bg-white text-slate-400 text-[8px] font-black uppercase tracking-widest border-b border-slate-100">
                <th className="px-6 py-4">Invoice</th>
                <th className="px-6 py-4">Pelanggan</th>
                <th className="px-6 py-4 text-right">Nilai Jual</th>
                <th className="px-6 py-4 text-right">Profit</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredOrders.map(order => {
                const orderRevenue = order.subtotal || 0;
                const orderCost = order.items.reduce((sum, item) => sum + (Number(item.costPrice || 0) * item.quantity), 0);
                const orderProfit = orderRevenue - orderCost;

                return (
                  <tr key={order.id} className="hover:bg-slate-50/50 transition-colors">
