import { supabase } from '../lib/supabase';
import { Customer, Product, Order } from '../types';

export const dbService = {
  // --- CUSTOMERS ---
  async getCustomers(): Promise<Customer[]> {
    const { data, error } = await supabase
      .from('customers')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error("Error fetch customers:", error.message);
      throw new Error(`Gagal memuat pelanggan: ${error.message}`);
    }
    return data || [];
  },

  async upsertCustomer(customer: Customer) {
    const { error } = await supabase
      .from('customers')
      .upsert(customer);

    if (error) {
      console.error("SUPABASE ERROR (upsertCustomer):", error);
      throw new Error(`Gagal simpan pelanggan: ${error.message}${error.details ? ' (' + error.details + ')' : ''}`);
    }
  },

  async deleteCustomer(id: string) {
    const { error } = await supabase
      .from('customers')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete customer:", error.message);
      throw new Error(`Gagal hapus pelanggan: ${error.message}`);
    }
  },

  // --- PRODUCTS ---
  async getProducts(): Promise<Product[]> {
    const { data, error } = await supabase
      .from('products')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error("Error fetch products:", error.message);
      throw new Error(`Gagal memuat barang: ${error.message}`);
    }
    return data || [];
  },

  async upsertProduct(product: Product) {
    const { error } = await supabase
      .from('products')
      .upsert(product);

    if (error) {
      console.error("SUPABASE ERROR DETAIL:", error);

      let friendlyMessage = error.message;
      if (error.message.includes("column 'costPrice'")) {
        friendlyMessage = "Kolom 'costPrice' belum ada di tabel products. Silakan tambahkan kolom tersebut di Supabase Dashboard.";
      }

      const detail = error.details ? ` - ${error.details}` : '';
      throw new Error(`Database Error: ${friendlyMessage}${detail}`);
    }
  },

  async deleteProduct(id: string) {
    const { error } = await supabase
      .from('products')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete product:", error.message);
      throw new Error(`Gagal hapus barang: ${error.message}`);
    }
  },

  // --- ORDERS ---
  async getOrders(): Promise<Order[]> {
    const { data, error } = await supabase
      .from('orders')
      .select('*')
      .order('orderDate', { ascending: false });

    if (error) {
      console.error("Error fetch orders:", error.message);
      throw new Error(`Gagal memuat order: ${error.message}`);
    }
    return data || [];
  },

  async upsertOrder(order: Order) {
    const { error } = await supabase
      .from('orders')
      .upsert(order);

    if (error) {
      console.error("SUPABASE ERROR (upsertOrder):", error);
      throw new Error(`Gagal simpan order: ${error.message}${error.details ? ' (' + error.details + ')' : ''}`);
    }
  },

  async deleteOrder(id: string) {
    const { error } = await supabase
      .from('orders')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete order:", error.message);
      throw new Error(`Gagal hapus order: ${error.message}`);
    }
  }
};

