  async upsertOrder(order: Order) {
    const { error } = await supabase
      .from('orders')
      .upsert(order);

    if (error) {
      console.error("SUPABASE ERROR (upsertOrder):", error);
      throw new Error(this.formatError(error, "simpan order"));
    }
  },

  async deleteOrder(id: string) {
    const { error } = await supabase
      .from('orders')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete order:", error);
      throw new Error(this.formatError(error, "hapus order"));
    }
  },

  // Helper untuk memformat pesan error Supabase
  formatError(error: any, action: string): string {
    const code = error.code || 'UNKNOWN';
    let message = error.message || 'Error tidak dikenal';

    if (code === '42P01') {
      message = `Tabel tidak ditemukan di database. Pastikan Anda sudah menjalankan SQL Setup di Supabase Editor.`;
    } else if (code === '42703' || message.toLowerCase().includes('column')) {
      message = `Struktur kolom database tidak sesuai (${message}). Jalankan SQL Setup kembali dan pastikan reload schema.`;
    } else if (code === 'PGRST103') {
      message = `Cache database belum diperbarui. Silakan jalankan 'NOTIFY pgrst, 'reload schema';' di SQL Editor.`;
    }

    return `Gagal ${action}: ${message} (Kode: ${code})`;
  }
};

