import { supabase } from '../lib/supabase';
import { Customer, Product, Order } from '../types';

export const dbService = {
  // --- CUSTOMERS ---
  async getCustomers(): Promise<Customer[]> {
    const { data, error } = await supabase
      .from('customers')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error("Error fetch customers:", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "memuat pelanggan"));
    }
    return data || [];
  },

  async upsertCustomer(customer: Customer) {
    const { error } = await supabase
      .from('customers')
      .upsert(customer);

    if (error) {
      console.error("SUPABASE ERROR (upsertCustomer):", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "simpan pelanggan"));
    }
  },

  async deleteCustomer(id: string) {
    const { error } = await supabase
      .from('customers')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete customer:", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "hapus pelanggan"));
    }
  },

  // --- PRODUCTS ---
  async getProducts(): Promise<Product[]> {
    const { data, error } = await supabase
      .from('products')
      .select('*')
      .order('name', { ascending: true });

    if (error) {
      console.error("Error fetch products:", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "memuat barang"));
    }
    return data || [];
  },

  async upsertProduct(product: Product) {
    // Memastikan data yang dikirim bersih
    const cleanData = {
      id: product.id,
      name: product.name,
      description: product.description,
      costPrice: Number(product.costPrice) || 0,
      priceJakarta: Number(product.priceJakarta) || 0,
      priceLuarKota: Number(product.priceLuarKota) || 0
    };

    const { error } = await supabase
      .from('products')
      .upsert(cleanData);

    if (error) {
      console.error("SUPABASE ERROR DETAIL (upsertProduct):", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "simpan barang"));
    }
  },

  async deleteProduct(id: string) {
    const { error } = await supabase
      .from('products')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete product:", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "hapus barang"));
    }
  },

  // --- ORDERS ---
  async getOrders(): Promise<Order[]> {
    const { data, error } = await supabase
      .from('orders')
      .select('*')
      .order('orderDate', { ascending: false });

    if (error) {
      console.error("Error fetch orders:", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "memuat order"));
    }
    return data || [];
  },

  async upsertOrder(order: Order) {
    const { error } = await supabase
      .from('orders')
      .upsert(order);

    if (error) {
      console.error("SUPABASE ERROR (upsertOrder):", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "simpan order"));
    }
  },

  async deleteOrder(id: string) {
    const { error } = await supabase
      .from('orders')
      .delete()
      .eq('id', id);

    if (error) {
      console.error("Error delete order:", JSON.stringify(error, null, 2));
      throw new Error(this.formatError(error, "hapus order"));
    }
  },

  // Helper untuk memformat pesan error Supabase
  formatError(error: any, action: string): string {
    const code = error.code || 'UNKNOWN';
    let message = error.message || 'Error tidak dikenal';

    if (code === 'PGRST204') {
      message = `Sinkronisasi skema database gagal. Nama kolom 'costPrice' tidak dikenali. Ini sering terjadi karena perbedaan huruf besar/kecil di Postgres. Klik tombol perbaikan di notifikasi.`;
    } else if (code === '42P01') {
      message = `Tabel tidak ditemukan. Jalankan SQL Setup awal di Supabase.`;
    } else if (code === '42703' || message.toLowerCase().includes('column')) {
      message = `Struktur kolom database tidak sesuai (${message}).`;
    }

    return `Gagal ${action}: ${message} (Kode: ${code})`;
  }
};

