export enum LocationType {
  JAKARTA = 'Jakarta',
  LUAR_KOTA = 'Luar Kota'
}

export enum OrderStatus {
  PENDING = 'PENDING',
  PAID = 'PAID',
  SHIPPED = 'SHIPPED',
  CANCELLED = 'CANCELLED'
}

export interface PaymentRecord {
  id: string;
  amount: number;
  date: string;
  note?: string;
}

export interface Customer {
  id: string;
  name: string;
  address: string;
  type: LocationType;
  email: string;
}

export interface Product {
  id: string;
  name: string;
  description: string;
  costPrice: number;
  priceJakarta: number;
  priceLuarKota: number;
}

export interface OrderItem {
  id: string;
  productId: string;
  name: string;
  quantity: number;
  unitPrice: number;
  costPrice: number; // Harga modal saat transaksi terjadi
}

export interface Order {
  id: string;
  invoiceNumber: string;
  customerId: string;
  customerName: string;
  customerEmail?: string;
  customerType: LocationType;
  customerAddress: string;
  orderDate: string;
  status: OrderStatus;
  items: OrderItem[];
  subtotal: number;
  downPayment: number;
  payments: PaymentRecord[];
  total: number;
  notes?: string;
}

export type ViewType = 'dashboard' | 'customers' | 'products' | 'orders' | 'invoice_detail' | 'reports' | 'manual_invoice';

export interface AppState {
  orders: Order[];
  customers: Customer[];
  products: Product[];
  activeOrder: Order | null;
  view: ViewType;
}

import React, { useState } from 'react';
import { Plus, Trash2, FilePlus, ChevronRight, Layout } from 'lucide-react';
import { Order, OrderItem, OrderStatus, LocationType } from '../types';
import InvoiceView from './InvoiceView';

interface Props {
  onNotify: (msg: string, type: 'success' | 'info') => void;
}

const ManualInvoiceManager: React.FC<Props> = ({ onNotify }) => {
  const [isPreview, setIsPreview] = useState(false);
  const [manualOrder, setManualOrder] = useState<Order | null>(null);

  const [customerName, setCustomerName] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [notes, setNotes] = useState('');
  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: '1', name: '', quantity: 1, unitPrice: 0 }
  ]);

  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', quantity: 1, unitPrice: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(items.filter(i => i.id !== id));
  };

  const updateItem = (id: string, field: string, value: any) => {
    setItems(items.map(i => i.id === id ? { ...i, [field]: value } : i));
  };

  const handlePreview = (e: React.FormEvent) => {
    e.preventDefault();
    const subtotal = items.reduce((sum, i) => sum + ((i.quantity || 0) * (i.unitPrice || 0)), 0);

    const order: Order = {
      id: 'manual_' + Date.now(),
      invoiceNumber: `M-${Date.now().toString().slice(-6)}`,
      customerId: 'manual',
      customerName,
      customerAddress,
      customerType: LocationType.JAKARTA,
      orderDate: new Date().toISOString(),
      status: OrderStatus.PENDING,
      items: items.map(i => ({
        id: i.id!,
        productId: 'manual',
        name: i.name || 'Barang Tanpa Nama',
        quantity: Number(i.quantity) || 0,
        unitPrice: Number(i.unitPrice) || 0,
        costPrice: 0
      })),
      subtotal,
      downPayment: 0,
      payments: [],
      total: subtotal,
      notes
    };

    setManualOrder(order);
    setIsPreview(true);
  };

  if (isPreview && manualOrder) {
    return (
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="flex items-center justify-between mb-8">
          <button onClick={() => setIsPreview(false)} className="text-slate-500 hover:text-indigo-600 font-bold text-xs uppercase tracking-widest flex items-center gap-2">
            ← Kembali Edit Data
          </button>
          <div className="bg-amber-100 text-amber-700 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-200">
            Mode Pratinjau Manual
          </div>
        </div>
        <InvoiceView order={manualOrder} onNotify={onNotify} />
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in duration-500">
      <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-8 md:p-12 overflow-hidden relative">
        <div className="absolute top-0 right-0 p-12 opacity-5"><FilePlus size={120} /></div>

        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-10">
            <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg shadow-indigo-200">
              <FilePlus size={24} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">Buat Nota Manual</h2>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Cepat & Tanpa Database</p>
            </div>
          </div>

          <form onSubmit={handlePreview} className="space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Pelanggan</label>
                <input 
                  required
                  placeholder="Ketik nama di sini..."
                  className="w-full px-6 py-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-bold text-sm focus:ring-4 focus:ring-indigo-500/10 transition-all"
                  value={customerName}
                  onChange={e => setCustomerName(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Alamat (Opsional)</label>
                <input 
                  placeholder="Alamat pelanggan..."
                  className="w-full px-6 py-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-bold text-sm focus:ring-4 focus:ring-indigo-500/10 transition-all"
                  value={customerAddress}
                  onChange={e => setCustomerAddress(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center px-1">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Daftar Item Barang</h3>
                <button type="button" onClick={addItem} className="text-[10px] font-black text-indigo-600 uppercase flex items-center gap-1 hover:opacity-70">
                  <Plus size={14} /> Tambah Baris
                </button>
              </div>

              <div className="space-y-3">
                {items.map((item) => (
                  <div key={item.id} className="grid grid-cols-12 gap-3 items-center bg-slate-50 p-3 rounded-2xl border border-slate-100 group transition-all hover:bg-white hover:border-indigo-100 hover:shadow-xl hover:shadow-indigo-500/5">
                    <div className="col-span-12 md:col-span-6">
                      <input 
                        required
                        placeholder="Nama barang..."
                        className="w-full px-4 py-2 bg-transparent outline-none font-bold text-slate-700 text-sm"
                        value={item.name}
                        onChange={e => updateItem(item.id!, 'name', e.target.value)}
                      />
                    </div>
                    <div className="col-span-4 md:col-span-2">
                      <div className="flex items-center">
                        <span className="text-[9px] font-black text-slate-300 uppercase mr-2">Qty</span>
                        <input 
                          required
                          type="number"
                          className="w-full bg-transparent outline-none font-black text-slate-700 text-sm"
                          value={item.quantity}
                          onChange={e => updateItem(item.id!, 'quantity', e.target.value)}
                        />
                      </div>
                    </div>
                    <div className="col-span-6 md:col-span-3">
                      <div className="flex items-center">
                        <span className="text-[9px] font-black text-slate-300 uppercase mr-2">Rp</span>
                        <input 
                          required
                          type="number"
                          className="w-full bg-transparent outline-none font-black text-slate-700 text-sm"
                          value={item.unitPrice}
                          onChange={e => updateItem(item.id!, 'unitPrice', e.target.value)}
                        />
                      </div>
                    </div>
                    <div className="col-span-2 md:col-span-1 flex justify-end">
                      <button type="button" onClick={() => removeItem(item.id!)} className="text-slate-300 hover:text-rose-500 transition-colors p-2">
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Catatan Nota</label>
              <textarea 
                className="w-full px-6 py-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-medium text-sm focus:ring-4 focus:ring-indigo-500/10 transition-all resize-none min-h-[80px]"
                placeholder="Misal: Barang yang sudah dibeli tidak dapat ditukar..."
                value={notes}
                onChange={e => setNotes(e.target.value)}
