            </div>

            <button 
              type="submit"
              className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] flex items-center justify-center gap-3 hover:bg-slate-800 transition-all shadow-2xl active:scale-95"
            >
              Pratinjau & Download Nota <ChevronRight size={18} />
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

