import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, CheckCircle2, Info, Loader2, Copy, AlertTriangle, FilePlus
} from 'lucide-react';
import { AppState, Order, Customer, Product, ViewType } from './types';
import Dashboard from './components/Dashboard';
import CustomerManager from './components/CustomerManager';
import ProductManager from './components/ProductManager';
import OrderManager from './components/OrderManager';
import InvoiceView from './components/InvoiceView';
import Reports from './components/Reports';
import ManualInvoiceManager from './components/ManualInvoiceManager';
import { dbService } from './services/dbService';
import { checkSupabaseConnection } from './lib/supabase';

interface Notification {
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
  sqlFix?: string;
}

const App: React.FC = () => {
  const [state, setState] = useState<AppState>({
    orders: [],
    customers: [],
    products: [],
    activeOrder: null,
    view: 'dashboard',
  });

  const [initialLoading, setInitialLoading] = useState(true);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [notification, setNotification] = useState<Notification | null>(null);
  const loadAttempted = useRef(false);

  const showNotify = useCallback((message: string, type: 'success' | 'error' | 'info' | 'warning' = 'success', sqlFix?: string) => {
    setNotification({ message, type, sqlFix });
    if (type !== 'error') {
      setTimeout(() => setNotification(null), 5000); 
    }
  }, []);

  const loadAllData = useCallback(async (isSilent = false) => {
    if (!isSilent) setInitialLoading(true);
    else setIsRefreshing(true);

    try {
      const connection = await checkSupabaseConnection();

      if (connection.connected) {
        const [customers, products, orders] = await Promise.all([
          dbService.getCustomers(),
          dbService.getProducts(),
          dbService.getOrders()
        ]);

        setState(prev => ({
          ...prev,
          customers: customers || [],
          products: products || [],
          orders: orders || []
        }));
        if (isSilent) showNotify("Data disinkronkan", "info");
      } else {
        showNotify(connection.message, "warning");
      }
    } catch (e: any) {
      console.error("Data load error:", e);
      showNotify("Gagal sinkronisasi data: " + (e.message || "Error tidak dikenal"), "error");
    } finally {
      setInitialLoading(false);
      setIsRefreshing(false);
    }
  }, [showNotify]);

  useEffect(() => {
    if (!loadAttempted.current) {
      loadAttempted.current = true;
      loadAllData();
    }
  }, [loadAllData]);

  const setView = useCallback((view: ViewType) => {
    setState(prev => ({ ...prev, view, activeOrder: null }));
    setIsMobileMenuOpen(false);
  }, []);

  const handleOptimizedAction = async (action: () => Promise<void>, updateState: () => void, successMsg: string) => {
    try {
      await action();
      updateState();
      showNotify(successMsg, 'success');
      return true;
    } catch (err: any) {
      console.error("ACTION ERROR DETAIL:", JSON.stringify(err, Object.getOwnPropertyNames(err), 2));

      let errorMsg = "Gagal memproses data";
      let sqlFix = undefined;

      const errString = JSON.stringify(err);
      if (errString.includes('PGRST204') || (err.message && err.message.includes('PGRST204'))) {
        errorMsg = "Database Tidak Sinkron. Jalankan perintah SQL di bawah untuk memperbaiki nama kolom.";
        sqlFix = `-- Perbaikan Casing Kolom & Reload Cache
ALTER TABLE products ADD COLUMN IF NOT EXISTS "costPrice" NUMERIC DEFAULT 0;
ALTER TABLE products ADD COLUMN IF NOT EXISTS "priceJakarta" NUMERIC DEFAULT 0;
ALTER TABLE products ADD COLUMN IF NOT EXISTS "priceLuarKota" NUMERIC DEFAULT 0;
NOTIFY pgrst, 'reload schema';`;
      } else {
        errorMsg = err.message || JSON.stringify(err);
      }

      showNotify(errorMsg, 'error', sqlFix);
      return false;
    }
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text).then(() => {
      showNotify("SQL Berhasil Disalin!", "success");
    });
  };

  const addCustomer = (c: Customer) => handleOptimizedAction(() => dbService.upsertCustomer(c), () => setState(prev => ({ ...prev, customers: [c, ...prev.customers] })), "Pelanggan disimpan");
  const updateCustomer = (c: Customer) => handleOptimizedAction(() => dbService.upsertCustomer(c), () => setState(prev => ({ ...prev, customers: prev.customers.map(item => item.id === c.id ? c : item) })), "Data diperbarui");
  const deleteCustomer = (id: string) => { if (window.confirm('Hapus pelanggan ini?')) handleOptimizedAction(() => dbService.deleteCustomer(id), () => setState(prev => ({ ...prev, customers: prev.customers.filter(item => item.id !== id) })), "Pelanggan dihapus"); };

  const addProduct = (p: Product) => handleOptimizedAction(() => dbService.upsertProduct(p), () => setState(prev => ({ ...prev, products: [p, ...prev.products] })), "Barang ditambahkan");
  const updateProduct = (p: Product) => handleOptimizedAction(() => dbService.upsertProduct(p), () => setState(prev => ({ ...prev, products: prev.products.map(item => item.id === p.id ? p : item) })), "Barang diperbarui");
  const deleteProduct = (id: string) => { if (window.confirm('Hapus barang ini?')) handleOptimizedAction(() => dbService.deleteProduct(id), () => setState(prev => ({ ...prev, products: prev.products.filter(item => item.id !== id) })), "Barang dihapus"); };

  const addOrder = async (o: Order) => handleOptimizedAction(async () => { await dbService.upsertOrder(o); setView('orders'); }, () => setState(prev => ({ ...prev, orders: [o, ...prev.orders] })), "Order berhasil dibuat");
  const updateOrder = async (o: Order) => handleOptimizedAction(() => dbService.upsertOrder(o), () => setState(prev => ({ ...prev, orders: prev.orders.map(item => item.id === o.id ? o : item) })), "Order diperbarui");
  const deleteOrder = (id: string) => { if (window.confirm('Hapus order ini?')) handleOptimizedAction(() => dbService.deleteOrder(id), () => setState(prev => ({ ...prev, orders: prev.orders.filter(item => item.id !== id) })), "Order dihapus"); };

  const viewInvoice = (order: Order) => setState(prev => ({ ...prev, activeOrder: order, view: 'invoice_detail' }));

  if (initialLoading) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-100 p-8 text-slate-400">
      <Loader2 className="w-10 h-10 animate-spin mb-4" />
      <p className="text-[10px] font-black uppercase tracking-[0.2em]">Memuat Sistem...</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col md:flex-row font-sans">
      {notification && (
        <div className={`fixed top-6 right-6 z-[100] flex flex-col gap-3 p-6 rounded-3xl shadow-2xl border animate-in slide-in-from-right-5 max-w-sm w-full ${
          notification.type === 'success' ? 'bg-indigo-600 border-indigo-500 text-white' : 
          notification.type === 'error' ? 'bg-rose-600 border-rose-500 text-white' : 
          'bg-slate-800 border-slate-700 text-white'
        }`}>
          <div className="flex items-start justify-between">
            <div className="flex-1">
               <p className="text-[9px] font-black uppercase tracking-widest opacity-60 mb-1">{notification.type}</p>
               <span className="text-sm font-bold leading-tight block">{notification.message}</span>
            </div>
            <button onClick={() => setNotification(null)} className="opacity-50 hover:opacity-100 ml-2"><X size={16}/></button>
          </div>

          {notification.sqlFix && (
            <div className="mt-2 space-y-3">
              <div className="p-3 bg-black/20 rounded-xl border border-white/10">
                 <p className="text-[8px] font-black uppercase text-white/40 mb-2">Perintah SQL Perbaikan:</p>
                 <code className="text-[9px] block bg-black/40 p-2 rounded-lg font-mono text-indigo-200 overflow-x-auto whitespace-pre no-scrollbar">
                   {notification.sqlFix}
                 </code>
              </div>
              <button 
                onClick={() => copyToClipboard(notification.sqlFix!)}
                className="w-full flex items-center justify-center gap-2 bg-white text-rose-600 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-100 transition-all shadow-lg active:scale-95"
              >
                <Copy size={12} /> Salin & Perbaiki Database
              </button>
            </div>
          )}
        </div>
      )}

      {/* Sidebar */}
      <aside className={`w-72 bg-slate-900 text-slate-300 flex flex-col fixed inset-y-0 left-0 z-50 transform transition-transform duration-300 ${isMobileMenuOpen ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0 md:sticky md:h-screen shadow-2xl`}>
        <div className="p-8 flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white"><Package size={20} /></div>
          <span className="text-lg font-black text-white uppercase tracking-tighter">Buku PO <span className="text-indigo-400">Online</span></span>
        </div>

        <nav className="flex-1 px-6 pb-6 space-y-1.5 overflow-y-auto no-scrollbar">
          <NavItem icon={<LayoutDashboard size={18} />} label="Beranda" active={state.view === 'dashboard'} onClick={() => setView('dashboard')} />
          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Aksi Cepat</div>
          <NavItem icon={<FilePlus size={18} />} label="Nota Manual" active={state.view === 'manual_invoice'} onClick={() => setView('manual_invoice')} />

          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Transaksi</div>
          <NavItem icon={<ShoppingCart size={18} />} label="Daftar Order" active={state.view === 'orders'} onClick={() => setView('orders')} />
          <NavItem icon={<BarChart3 size={18} />} label="Laporan" active={state.view === 'reports'} onClick={() => setView('reports')} />

          <div className="pt-6 pb-2 px-3 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Data Master</div>
          <NavItem icon={<Users size={18} />} label="Pelanggan" active={state.view === 'customers'} onClick={() => setView('customers')} />
          <NavItem icon={<Box size={18} />} label="Katalog Barang" active={state.view === 'products'} onClick={() => setView('products')} />
        </nav>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white/80 backdrop-blur-lg border-b border-slate-200 h-16 flex items-center px-6 md:px-10 sticky top-0 z-30 justify-between">
           <div className="flex items-center gap-4">
             <button onClick={() => setIsMobileMenuOpen(true)} className="md:hidden text-slate-600"><Menu size={24}/></button>
             <h2 className="text-sm font-black text-slate-900 uppercase tracking-widest">{state.view.replace('_', ' ')}</h2>
           </div>
           <div className="flex items-center gap-4">
             {isRefreshing && <div className="flex items-center gap-2"><Loader2 size={12} className="animate-spin text-indigo-500" /><span className="text-[9px] font-black text-indigo-500">REFRESHING...</span></div>}
             <button onClick={() => loadAllData(true)} className="p-2 text-slate-400 hover:text-indigo-600"><Info size={18}/></button>
           </div>
        </header>

        <div className="flex-1 overflow-y-auto no-scrollbar scroll-smooth">
          <div className="p-4 md:p-8 lg:p-12 max-w-7xl mx-auto">
            {state.view === 'dashboard' && <Dashboard state={state} onNavigate={setView} onDeleteOrder={deleteOrder} />}
            {state.view === 'manual_invoice' && <ManualInvoiceManager onNotify={showNotify} />}
            {state.view === 'customers' && <CustomerManager customers={state.customers} onAdd={addCustomer} onUpdate={updateCustomer} onDelete={deleteCustomer} />}
            {state.view === 'products' && <ProductManager products={state.products} onAdd={addProduct} onUpdate={updateProduct} onDelete={deleteProduct} />}
            {state.view === 'orders' && <OrderManager state={state} onAddOrder={addOrder} onUpdateOrder={updateOrder} onDeleteOrder={deleteOrder} onViewInvoice={viewInvoice} />}
            {state.view === 'reports' && <Reports state={state} />}
            {state.view === 'invoice_detail' && state.activeOrder && (
              <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                <button onClick={() => setView('orders')} className="text-slate-500 hover:text-indigo-600 mb-6 font-bold text-xs uppercase tracking-widest">← Kembali</button>
                <InvoiceView order={state.activeOrder} onNotify={showNotify} />
              </div>
            )}
          </div>
        </div>
      </main>

      {isMobileMenuOpen && <div className="fixed inset-0 bg-slate-900/40 z-40 md:hidden" onClick={() => setIsMobileMenuOpen(false)} />}
    </div>
  );
};

const NavItem = ({ icon, label, active, onClick }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-bold text-sm transition-all ${active ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/20' : 'hover:bg-slate-800 text-slate-400 hover:text-white'}`}>
    {icon} <span>{label}</span>
  </button>
);

export default App;

import React, { useState, useMemo } from 'react';
import { Plus, Trash2, FilePlus, ChevronRight, Calculator } from 'lucide-react';
import { Order, OrderItem, OrderStatus, LocationType } from '../types';
import InvoiceView from './InvoiceView';

interface Props {
  onNotify: (msg: string, type: 'success' | 'info') => void;
}

const ManualInvoiceManager: React.FC<Props> = ({ onNotify }) => {
  const [isPreview, setIsPreview] = useState(false);
  const [manualOrder, setManualOrder] = useState<Order | null>(null);

  const [customerName, setCustomerName] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [notes, setNotes] = useState('');
  const [items, setItems] = useState<Partial<OrderItem>[]>([
    { id: '1', name: '', quantity: 1, unitPrice: 0 }
  ]);

  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), name: '', quantity: 1, unitPrice: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(items.filter(i => i.id !== id));
  };

  const updateItem = (id: string, field: string, value: any) => {
    setItems(items.map(i => i.id === id ? { ...i, [field]: value } : i));
  };

  // Kalkulasi total seluruh item untuk ditampilkan di form
  const formSubtotal = useMemo(() => {
    return items.reduce((sum, i) => sum + (Number(i.quantity || 0) * Number(i.unitPrice || 0)), 0);
  }, [items]);

  const handlePreview = (e: React.FormEvent) => {
    e.preventDefault();

    const order: Order = {
      id: 'manual_' + Date.now(),
      invoiceNumber: `M-${Date.now().toString().slice(-6)}`,
      customerId: 'manual',
      customerName,
      customerAddress,
      customerType: LocationType.JAKARTA,
      orderDate: new Date().toISOString(),
      status: OrderStatus.PENDING,
      items: items.map(i => ({
        id: i.id!,
        productId: 'manual',
        name: i.name || 'Barang Tanpa Nama',
        quantity: Number(i.quantity) || 0,
        unitPrice: Number(i.unitPrice) || 0,
        costPrice: 0
      })),
      subtotal: formSubtotal,
      downPayment: 0,
      payments: [],
      total: formSubtotal,
      notes
    };

    setManualOrder(order);
    setIsPreview(true);
  };

  if (isPreview && manualOrder) {
    return (
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="flex items-center justify-between mb-8">
          <button onClick={() => setIsPreview(false)} className="text-slate-500 hover:text-indigo-600 font-bold text-xs uppercase tracking-widest flex items-center gap-2">
            ← Kembali Edit Data
          </button>
          <div className="bg-amber-100 text-amber-700 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-200">
            Mode Pratinjau Manual
          </div>
        </div>
        <InvoiceView order={manualOrder} onNotify={onNotify} />
      </div>
    );
  }

  return (
    <div className="max-w-5xl mx-auto animate-in fade-in duration-500">
      <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 p-8 md:p-12 overflow-hidden relative">
        <div className="absolute top-0 right-0 p-12 opacity-5"><FilePlus size={120} /></div>

        <div className="relative z-10">
          <div className="flex items-center gap-3 mb-10">
            <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-lg shadow-indigo-200">
              <FilePlus size={24} />
            </div>
            <div>
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">Buat Nota Manual</h2>
              <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Ketik Bebas & Langsung Cetak</p>
            </div>
          </div>

          <form onSubmit={handlePreview} className="space-y-10">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Nama Pelanggan</label>
                <input 
                  required
                  placeholder="Ketik nama di sini..."
                  className="w-full px-6 py-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-bold text-sm focus:ring-4 focus:ring-indigo-500/10 transition-all"
                  value={customerName}
                  onChange={e => setCustomerName(e.target.value)}
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Alamat (Opsional)</label>
                <input 
                  placeholder="Alamat pelanggan..."
                  className="w-full px-6 py-4 rounded-2xl border border-slate-200 bg-slate-50 outline-none font-bold text-sm focus:ring-4 focus:ring-indigo-500/10 transition-all"
                  value={customerAddress}
                  onChange={e => setCustomerAddress(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-4">
              <div className="flex justify-between items-center px-1">
                <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
                  <Calculator size={14} className="text-indigo-500" /> Daftar Item Barang
                </h3>
                <button type="button" onClick={addItem} className="text-[10px] font-black text-indigo-600 uppercase flex items-center gap-1 hover:opacity-70 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-100">
