const supabaseAnonKey = (import.meta.env?.VITE_SUPABASE_ANON_KEY || process.env?.SUPABASE_ANON_KEY || 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImtlZHZqaXl0dmdzdmFiZmJlZGJwIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjYwMzU5OTAsImV4cCI6MjA4MTYxMTk5MH0.So64IY0G1y9nrKGI0lAi0acP0vFsG0ABIeXYTCz5Oh4').trim();

// Validasi kredensial
if (!supabaseUrl || supabaseUrl === '' || supabaseUrl.includes('undefined')) {
