export const checkSupabaseConnection = async () => {
  try {
    const startTime = Date.now();
    // Gunakan rpc atau query tabel dasar untuk cek status
    const { data, error, status } = await supabase
      .from('customers')
      .select('id')
      .limit(1);

    const duration = Date.now() - startTime;

    if (error) {
      console.warn("Supabase Check:", { status, code: error.code, message: error.message });

      // Error code 'PGRST301' atau '503' biasanya berarti project dipause oleh Supabase
      if (error.code === 'PGRST301' || status === 503 || error.message.includes('paused')) {
        return { 
          connected: false, 
          isPaused: true,
          message: "Project Supabase Sedang Di-Pause (Inaktif)" 
        };
      }

      if (error.code === '42P01') {
        return { connected: false, isPaused: false, message: "Tabel Database Belum Dibuat" };
      }

      return { connected: false, isPaused: false, message: `Database Error: ${error.code}` };
    }

    return { connected: true, isPaused: false, message: "Cloud Terhubung", latency: duration };
  } catch (err: any) {
    console.error("Supabase Connectivity Exception:", err);
    return { connected: false, isPaused: false, message: "Gagal Menghubungi Server Database" };
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { 
  LayoutDashboard, Users, Box, ShoppingCart, BarChart3, 
  Package, Menu, X, CheckCircle2, Info, Loader2, Copy, AlertTriangle, FilePlus, RefreshCw, Database
