        <Package size={48} className="text-rose-500 relative animate-bounce" />
      </div>
      <Loader2 className="w-6 h-6 animate-spin mb-4 text-slate-600" />
      <p className="text-[10px] font-black uppercase tracking-[0.3em]">Menghubungkan ke Cloud...</p>
    </div>
  );

  // Paused Project UI (Supabase Inactivity)
  if (isPaused) return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 p-6 text-center">
      <div className="bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-200 max-w-md w-full">
        <div className="bg-amber-100 w-20 h-20 rounded-3xl flex items-center justify-center text-amber-600 mx-auto mb-8 shadow-inner">
          <AlertTriangle size={40} />
        </div>
        <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight mb-4">Database Paused</h2>
        <p className="text-slate-500 text-sm font-medium leading-relaxed mb-8">
          Sistem cloud (Supabase) terdeteksi dalam status <b>Paused</b> karena tidak ada aktivitas dalam 7 hari terakhir.
        </p>
        <div className="bg-slate-50 p-6 rounded-2xl mb-8 border border-slate-100 text-left">
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Cara Memperbaiki:</p>
          <ol className="text-xs text-slate-600 space-y-2 list-decimal list-inside font-medium">
            <li>Buka <b>dashboard.supabase.com</b></li>
            <li>Pilih project <b>kedvjiyt...</b></li>
            <li>Klik tombol <b>"Restore Project"</b></li>
            <li>Tunggu 2-3 menit & muat ulang halaman ini.</li>
          </ol>
        </div>
        <button 
          onClick={() => loadAllData()}
          className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-black transition-all shadow-xl active:scale-95"
        >
          <RefreshCw size={16} /> MUAT ULANG SISTEM
        </button>
      </div>
      <p className="mt-8 text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">Buku PO Online Management</p>
    </div>
  );

  return (
    <div className="min-h-screen bg-slate-100 flex flex-col md:flex-row font-sans">
      {notification && (
        <div className={`fixed top-6 right-6 z-[100] flex flex-col gap-3 p-6 rounded-3xl shadow-2xl border animate-in slide-in-from-right-5 max-w-sm w-full ${
          notification.type === 'success' ? 'bg-indigo-600 border-indigo-500 text-white' : 
          notification.type === 'error' ? 'bg-rose-600 border-rose-500 text-white' : 
          'bg-slate-800 border-slate-700 text-white'
        }`}>
          <div className="flex items-start justify-between">
            <div className="flex-1">
               <p className="text-[9px] font-black uppercase tracking-widest opacity-60 mb-1">{notification.type}</p>
               <span className="text-sm font-bold leading-tight block">{notification.message}</span>
            </div>
            <button onClick={() => setNotification(null)} className="opacity-50 hover:opacity-100 ml-2"><X size={16}/></button>
          </div>

          {notification.sqlFix && (
            <div className="mt-2 space-y-3">
              <div className="p-3 bg-black/20 rounded-xl border border-white/10">
                 <p className="text-[8px] font-black uppercase text-white/40 mb-2">Perintah SQL Perbaikan:</p>
                 <code className="text-[9px] block bg-black/40 p-2 rounded-lg font-mono text-indigo-200 overflow-x-auto whitespace-pre no-scrollbar">
                   {notification.sqlFix}
