    }

    return { connected: true, isPaused: false, message: "Cloud Terhubung", latency: duration };
  } catch (err: any) {
    console.error("Supabase Connectivity Exception:", err);
    return { connected: false, isPaused: false, message: "Gagal Menghubungi Server Database" };
  }
};

