import { GoogleGenAI } from "@google/genai";
import { Order } from "../types";

export const getSmartOrderSummary = async (order: Order): Promise<string> => {
  // Ensure the API key is retrieved exclusively from process.env.API_KEY as per guidelines
  if (!process.env.API_KEY) {
    return "Ringkasan otomatis tidak aktif (API Key belum diatur di server).";
  }

  try {
    // Initialize GoogleGenAI with a named parameter and direct process.env reference
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Call generateContent with the appropriate model name and direct prompt string
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Buat ringkasan pesanan singkat dalam 1-2 kalimat ramah untuk pelanggan ${order.customerName}. 
      Invoice: ${order.invoiceNumber}. 
      Total Belanja: Rp ${order.subtotal.toLocaleString()}. 
      Status: ${order.total <= 0 ? 'Lunas' : 'Sisa tagihan Rp ' + order.total.toLocaleString()}.
      Daftar barang: ${order.items.map(i => i.name).join(', ')}.`,
      config: {
        temperature: 0.6,
      }
    });

    // Extract text output using the .text property (not a method)
    return response.text || "Pesanan telah dikonfirmasi dengan rincian di atas.";
  } catch (error: any) {
    console.warn("AI summary error:", error.message);
    return "Ringkasan pesanan sudah tersedia pada detail nota.";
  }
};

