const CACHE_NAME = 'bukupo-v12';
const ASSETS = [
  './',
  './index.html',
  './manifest.json?v=12'
];

// Install Event
self.addEventListener('install', (event) => {
  self.skipWaiting(); 
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => {
      return cache.addAll(ASSETS);
    })
  );
});

// Activate Event
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((keys) => {
      return Promise.all(
        keys.filter((key) => key !== CACHE_NAME).map((key) => caches.delete(key))
      );
    })
  );
});

// Fetch Event - Improved with Network-First for Navigation
self.addEventListener('fetch', (event) => {
  // Hanya tangani request GET
  if (event.request.method !== 'GET') return;

  const url = new URL(event.request.url);

  // Jika navigasi (index.html), gunakan Network-First agar selalu terbaru
  if (event.request.mode === 'navigate') {
    event.respondWith(
      fetch(event.request).catch(() => caches.match('./index.html'))
    );
    return;
  }

  // Untuk aset lain (data URIs, dll), gunakan Cache-First
  event.respondWith(
    caches.match(event.request).then((cachedResponse) => {
      return cachedResponse || fetch(event.request).catch(() => {
        // Fallback jika benar-benar offline dan tidak ada di cache
        if (event.request.destination === 'image') return caches.match('./favicon.ico');
      });
    })
  );
});

