import { Order, OrderItem, OrderStatus, LocationType } from '../types';

interface OrderFormProps {
  onSubmit: (order: Order) => void;
}

const OrderForm: React.FC<OrderFormProps> = ({ onSubmit }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerEmail, setCustomerEmail] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [notes, setNotes] = useState('');
  // Added costPrice: 0 to match OrderItem interface
  const [items, setItems] = useState<OrderItem[]>([
    { id: Math.random().toString(36).substr(2, 9), productId: 'AD-HOC', name: '', quantity: 1, unitPrice: 0, costPrice: 0 }
  ]);

  // Added costPrice: 0 to match OrderItem interface when adding a new item
  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), productId: 'AD-HOC', name: '', quantity: 1, unitPrice: 0, costPrice: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(items.filter(item => item.id !== id));
    }
  };

  const updateItem = (id: string, field: keyof OrderItem, value: any) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const calculateTotal = () => {
    return items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = calculateTotal();

    // Fixed: Added missing 'payments' property for the Order interface
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      invoiceNumber: `INV-${Date.now().toString().slice(-6)}`,
      customerId: 'AD-HOC',
      customerName,
      customerEmail,
      customerType: LocationType.JAKARTA,
      customerAddress,
      orderDate: new Date().toISOString(),
      status: OrderStatus.PENDING,
      items,
      subtotal: total,
      downPayment: 0,
      payments: [],
      total: total,
      notes
    };

    onSubmit(newOrder);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl shadow-gray-200 border border-gray-100 p-8">
      <h2 className="text-2xl font-bold text-gray-900 mb-8">Form Pesanan Baru</h2>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Nama Pelanggan</label>
            <input 
              required
              type="text" 
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="Contoh: Budi Santoso"
              value={customerName}
              onChange={(e) => setCustomerName(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Email Pelanggan</label>
            <input 
              required
              type="email" 
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="budi@email.com"
              value={customerEmail}
              onChange={(e) => setCustomerEmail(e.target.value)}
            />
          </div>
          <div className="md:col-span-2 space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Alamat Pengiriman</label>
            <textarea 
              required
              rows={3}
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
              placeholder="Jl. Merdeka No. 123, Jakarta"
              value={customerAddress}
              onChange={(e) => setCustomerAddress(e.target.value)}
            />
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-bold text-gray-900">Daftar Barang</h3>
            <button 
              type="button"
              onClick={addItem}
              className="flex items-center gap-1 text-sm text-indigo-600 hover:text-indigo-700 font-semibold"
            >
              <Plus className="w-4 h-4" />
              Tambah Item
            </button>
          </div>

          <div className="space-y-3">
            {items.map((item, index) => (
              <div key={item.id} className="grid grid-cols-12 gap-3 items-end bg-gray-50 p-4 rounded-xl border border-gray-200">
                <div className="col-span-12 md:col-span-6 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Nama Barang</label>
                  <input 
                    required
                    type="text"
                    placeholder="Nama Barang"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.name}
                    onChange={(e) => updateItem(item.id, 'name', e.target.value)}
                  />
                </div>
                <div className="col-span-4 md:col-span-2 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Qty</label>
                  <input 
                    required
                    type="number"
                    min="1"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.quantity}
                    onChange={(e) => updateItem(item.id, 'quantity', parseInt(e.target.value) || 0)}
                  />
                </div>
                <div className="col-span-5 md:col-span-3 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Harga Satuan</label>
                  <input 
                    required
                    type="number"
                    min="0"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.unitPrice}
                    onChange={(e) => updateItem(item.id, 'unitPrice', parseInt(e.target.value) || 0)}
                  />
                </div>
                <div className="col-span-3 md:col-span-1 flex justify-center pb-2">
                  <button 
                    type="button"
                    onClick={() => removeItem(item.id)}
                    className="text-red-400 hover:text-red-600 transition-colors"
