        </div>

        <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Catatan (Opsional)</label>
            <textarea 
              rows={2}
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
              placeholder="Catatan tambahan untuk pesanan ini..."
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            />
          </div>

        <div className="pt-6 border-t border-gray-100 flex items-center justify-between">
          <div className="text-gray-500">
            Total Pembayaran: <span className="text-2xl font-bold text-gray-900">Rp {calculateTotal().toLocaleString()}</span>
          </div>
          <button 
            type="submit"
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg shadow-indigo-100"
          >
            <Save className="w-5 h-5" />
            Simpan Pesanan
          </button>
        </div>
      </form>
    </div>
  );
};

