import { Download, Share2, Sparkles, Image as ImageIcon, FileText, Loader2 } from 'lucide-react';
import { Order } from '../types';
import { getSmartOrderSummary } from '../services/geminiService';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface InvoiceViewProps {
  order: Order;
  onNotify?: (msg: string, type: 'success' | 'info') => void;
}

const InvoiceView: React.FC<InvoiceViewProps> = ({ order, onNotify }) => {
  const invoiceRef = useRef<HTMLDivElement>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    // Start AI fetch without blocking component render
    const fetchSummary = async () => {
      setIsAiLoading(true);
      try {
        const summary = await getSmartOrderSummary(order);
        text(summary);
      } catch (e) {
        setAiSummary("Ringkasan tidak tersedia.");
      } finally {
        setIsAiLoading(false);
      }
    };

    setAiSummary(''); // Reset for new order
    fetchSummary();
  }, [order.id]); // Only refetch if order ID changes

  const handleDownloadJPG = async () => {
    if (!invoiceRef.current) return;
    try {
      if (onNotify) onNotify("Menyiapkan Gambar...", "info");
      const canvas = await html2canvas(invoiceRef.current, { 
        scale: 2,
        useCORS: true,
        logging: false
      });
      const link = document.createElement('a');
      link.download = `NOTA-${order.invoiceNumber}.jpg`;
      link.href = canvas.toDataURL('image/jpeg', 0.9);
      link.click();
      if (onNotify) onNotify("Berhasil simpan JPG", "success");
    } catch (e) {
      if (onNotify) onNotify("Gagal ekspor gambar", "info");
    }
  };

  const handleDownloadPDF = async () => {
    if (!invoiceRef.current) return;
    try {
      if (onNotify) onNotify("Membuat PDF...", "info");
      const canvas = await html2canvas(invoiceRef.current, { 
        scale: 2, 
        useCORS: true,
        logging: false
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`NOTA-${order.invoiceNumber}.pdf`);
      if (onNotify) onNotify("Berhasil simpan PDF", "success");
    } catch (e) {
      if (onNotify) onNotify("Gagal ekspor PDF", "info");
    }
  };

  function text(summary: string): void {
    setAiSummary(summary);
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest px-2">Dokumen Nota</h3>
            <div className="flex gap-2">
                <button onClick={handleDownloadJPG} className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-100 transition-all" title="Simpan JPG"><ImageIcon size={18} /></button>
                <button onClick={handleDownloadPDF} className="flex items-center gap-2 px-4 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 text-xs font-bold transition-all shadow-lg shadow-indigo-100"><FileText size={16} /> PDF</button>
            </div>
        </div>

        <div ref={invoiceRef} className="bg-white shadow-xl p-8 md:p-14 text-slate-800 border border-slate-100 rounded-lg origin-top" style={{ width: '100%', maxWidth: '800px', margin: '0 auto' }}>
          <div className="flex justify-between items-start border-b-2 border-slate-900 pb-8 mb-10">
            <div>
              <h1 className="text-3xl font-black text-slate-900 tracking-tighter uppercase">Nota</h1>
              <p className="text-slate-400 mt-1 font-bold tracking-widest uppercase text-[10px]">{order.invoiceNumber}</p>
            </div>
            <div className="text-right">
                <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Tanggal</p>
                <p className="font-bold text-slate-800 text-sm">{new Date(order.orderDate).toLocaleDateString('id-ID', { dateStyle: 'long' })}</p>
            </div>
          </div>

          <div className="mb-12">
            <h4 className="text-[9px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-2">Kepada</h4>
            <p className="text-lg font-black text-slate-900 leading-none">{order.customerName}</p>
            {order.customerAddress && <p className="text-xs text-slate-500 mt-2 font-medium leading-relaxed max-w-sm whitespace-pre-wrap">{order.customerAddress}</p>}
          </div>

          <table className="w-full mb-10">
            <thead>
              <tr className="border-b border-slate-200 text-left">
                <th className="py-3 text-[10px] font-black uppercase tracking-widest text-slate-400">Barang</th>
                <th className="py-3 px-4 text-[10px] font-black uppercase text-center text-slate-400">Qty</th>
                <th className="py-3 text-[10px] font-black uppercase text-right text-slate-400">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {order.items.map((item) => (
                <tr key={item.id}>
                  <td className="py-4 pr-4 text-xs font-bold text-slate-800">{item.name}</td>
                  <td className="py-4 px-4 text-xs text-center font-medium text-slate-600">{item.quantity}</td>
