        <button className="w-full flex items-center justify-center gap-3 bg-emerald-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-100"><Share2 size={16} /> Bagikan WhatsApp</button>
