              <option value={LocationType.LUAR_KOTA}>Luar Kota (Harga Luar Kota)</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Email (Opsional)</label>
