            </button>
            <button type="button" onClick={resetForm} className="bg-slate-100 text-slate-600 px-6 py-2 rounded-lg font-bold text-sm">Batal</button>
          </div>
        </form>
      )}

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden overflow-x-auto">
