              <button onClick={handleDownloadPDF} className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"><FileText size={14} /> PDF</button>
           </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 items-end border-t border-slate-100 pt-6">
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Rentang Cepat</label>
            <div className="flex gap-1">
              {['today', 'week', 'month'].map(t => (
                <button key={t} onClick={() => setPreset(t as any)} className="flex-1 px-2 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[9px] font-bold text-slate-600 uppercase">
                  {t === 'today' ? 'Hari ini' : t === 'week' ? '7 Hari' : '30 Hari'}
                </button>
              ))}
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pelanggan</label>
            <select className="w-full px-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={filterCustomer} onChange={e => setFilterCustomer(e.target.value)}>
              <option value="all">Semua Pelanggan</option>
              {state.customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div className="space-y-2 md:col-span-2">
            <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest ml-1">Pencarian</label>
            <div className="relative">
              <input type="text" placeholder="Cari invoice atau nama..." className="w-full pl-8 pr-3 py-1.5 rounded-xl bg-slate-50 border border-slate-200 text-[11px] font-bold text-slate-700 outline-none" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
              <Search className="absolute left-2.5 top-2 text-slate-300" size={12} />
            </div>
          </div>
        </div>
      </div>

      <div ref={reportRef} className="bg-slate-100 p-6 md:p-10 rounded-[2.5rem] space-y-6 text-slate-900 border border-slate-200 shadow-inner">
