import { Order } from '../types';
import { getSmartOrderSummary } from '../services/geminiService';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jspdf';

interface InvoiceViewProps {
  order: Order;
  onNotify?: (msg: string, type: 'success' | 'info') => void;
}

const InvoiceView: React.FC<InvoiceViewProps> = ({ order, onNotify }) => {
  const invoiceRef = useRef<HTMLDivElement>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    // Start AI fetch without blocking component render
    const fetchSummary = async () => {
      setIsAiLoading(true);
      try {
        const summary = await getSmartOrderSummary(order);
        setAiSummary(summary);
      } catch (e) {
        setAiSummary("Ringkasan tidak tersedia.");
      } finally {
        setIsAiLoading(false);
      }
    };

    setAiSummary(''); // Reset for new order
    fetchSummary();
  }, [order.id]); // Only refetch if order ID changes

  const handleDownloadJPG = async () => {
    if (!invoiceRef.current) return;
    try {
      if (onNotify) onNotify("Menyiapkan Gambar...", "info");
      const canvas = await html2canvas(invoiceRef.current, { 
        scale: 2,
        useCORS: true,
        logging: false
      });
      const link = document.createElement('a');
      link.download = `NOTA-${order.invoiceNumber}.jpg`;
      link.href = canvas.toDataURL('image/jpeg', 0.9);
      link.click();
      if (onNotify) onNotify("Berhasil simpan JPG", "success");
    } catch (e) {
      if (onNotify) onNotify("Gagal ekspor gambar", "info");
    }
  };

  const handleDownloadPDF = async () => {
    if (!invoiceRef.current) return;
    try {
      if (onNotify) onNotify("Membuat PDF...", "info");
      const canvas = await html2canvas(invoiceRef.current, { 
        scale: 2, 
        useCORS: true,
        logging: false
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`NOTA-${order.invoiceNumber}.pdf`);
      if (onNotify) onNotify("Berhasil simpan PDF", "success");
    } catch (e) {
      if (onNotify) onNotify("Gagal ekspor PDF", "info");
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest px-2">Dokumen Nota</h3>
            <div className="flex gap-2">
                <button onClick={handleDownloadJPG} className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-100 transition-all" title="Simpan JPG"><ImageIcon size={18} /></button>
                <button onClick={handleDownloadPDF} className="flex items-center gap-2 px-4 py-2.5 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 text-xs font-bold transition-all shadow-lg shadow-indigo-100"><FileText size={16} /> PDF</button>
            </div>
        </div>

        <div ref={invoiceRef} className="bg-white shadow-xl p-8 md:p-14 text-slate-800 border border-slate-100 rounded-lg origin-top" style={{ width: '100%', maxWidth: '800px', margin: '0 auto' }}>
          <div className="flex justify-between items-start border-b-2 border-slate-900 pb-8 mb-10">
            <div>
              <h1 className="text-3xl font-black text-slate-900 tracking-tighter uppercase">Nota</h1>
              <p className="text-slate-400 mt-1 font-bold tracking-widest uppercase text-[10px]">{order.invoiceNumber}</p>
            </div>
            <div className="text-right">
                <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Tanggal</p>
                <p className="font-bold text-slate-800 text-sm">{new Date(order.orderDate).toLocaleDateString('id-ID', { dateStyle: 'long' })}</p>
            </div>
          </div>

          <div className="mb-12">
            <h4 className="text-[9px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-2">Kepada</h4>
            <p className="text-lg font-black text-slate-900 leading-none">{order.customerName}</p>
            {order.customerAddress && <p className="text-xs text-slate-500 mt-2 font-medium leading-relaxed max-w-sm whitespace-pre-wrap">{order.customerAddress}</p>}
          </div>

          <table className="w-full mb-10">
            <thead>
              <tr className="border-b border-slate-200 text-left">
                <th className="py-3 text-[10px] font-black uppercase tracking-widest text-slate-400">Barang</th>
                <th className="py-3 px-2 text-[10px] font-black uppercase text-right text-slate-400">Harga</th>
                <th className="py-3 px-4 text-[10px] font-black uppercase text-center text-slate-400">Qty</th>
                <th className="py-3 text-[10px] font-black uppercase text-right text-slate-400">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {order.items.map((item) => (
                <tr key={item.id}>
                  <td className="py-4 pr-2 text-xs font-bold text-slate-800">{item.name}</td>
                  <td className="py-4 px-2 text-[11px] text-right font-medium text-slate-500">Rp {item.unitPrice.toLocaleString()}</td>
                  <td className="py-4 px-4 text-xs text-center font-medium text-slate-600">{item.quantity}</td>
                  <td className="py-4 text-xs text-right font-black text-slate-900">Rp {(item.quantity * item.unitPrice).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>

          <div className="flex justify-end pt-6 border-t border-slate-100">
            <div className="w-full max-w-[280px] space-y-3">
              <div className="flex justify-between text-[11px] font-bold">
                <span className="text-slate-400 uppercase tracking-widest">Jumlah</span>
                <span className="text-slate-800">Rp {order.subtotal.toLocaleString()}</span>
              </div>

              {order.payments && order.payments.length > 0 && (
                <div className="space-y-2 py-2">
                  {order.payments.map((p, idx) => (
                    <div key={p.id} className="flex justify-between text-[11px]">
                      <span className="text-emerald-500 italic">
                        {order.payments.length === 1 ? 'DP' : `DP ${idx + 1}`}
                      </span>
                      <span className="text-emerald-600 font-bold">- Rp {p.amount.toLocaleString()}</span>
                    </div>
                  ))}
                </div>
              )}

              <div className="pt-4 border-t-2 border-slate-900 flex justify-between items-baseline">
                <span className="text-[10px] font-black text-slate-900 uppercase">Subtotal</span>
                <span className="text-2xl font-black text-indigo-600">Rp {order.total.toLocaleString()}</span>
              </div>
            </div>
          </div>

          <div className="mt-20 pt-10 border-t border-slate-50 text-center">
             {order.notes && (
               <div className="mb-6 text-left p-4 bg-slate-50 rounded-xl border border-slate-100">
                  <p className="text-[9px] font-black text-slate-400 uppercase mb-1 tracking-widest">Catatan:</p>
                  <p className="text-xs text-slate-500 italic font-medium leading-relaxed">"{order.notes}"</p>
               </div>
             )}
             <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.4em]">Terima Kasih</p>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="bg-slate-900 rounded-[2rem] p-8 text-white shadow-2xl relative overflow-hidden group">
          <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:scale-110 transition-transform"><Sparkles size={100} /></div>
          <div className="relative z-10">
            <div className="flex items-center gap-2 mb-4 text-indigo-400 font-black text-xs uppercase tracking-[0.2em]"><Sparkles size={14} /> Ringkasan AI</div>
            {isAiLoading ? (
              <div className="space-y-3 animate-pulse">
                <div className="h-2 bg-slate-800 rounded-full w-full"></div>
                <div className="h-2 bg-slate-800 rounded-full w-4/5"></div>
                <div className="flex items-center gap-2 mt-2">
                   <Loader2 size={12} className="animate-spin text-slate-600" />
                   <span className="text-[10px] text-slate-600 font-bold uppercase">Memproses AI...</span>
                </div>
              </div>
            ) : (
              <p className="text-sm text-slate-300 italic font-medium leading-relaxed">"{aiSummary || 'Menunggu data...'}"</p>
            )}
          </div>
        </div>
        <button className="w-full flex items-center justify-center gap-3 bg-emerald-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-100"><Share2 size={16} /> Bagikan WhatsApp</button>
      </div>
    </div>
  );
};

export default InvoiceView;

import React, { useState } from 'react';
// Removed redundant global JSX declaration to fix duplicate index signature error.
import { Plus, Trash2, Save } from 'lucide-react';
import { Order, OrderItem, OrderStatus, LocationType } from '../types';

interface OrderFormProps {
  onSubmit: (order: Order) => void;
}

const OrderForm: React.FC<OrderFormProps> = ({ onSubmit }) => {
  const [customerName, setCustomerName] = useState('');
  const [customerEmail, setCustomerEmail] = useState('');
  const [customerAddress, setCustomerAddress] = useState('');
  const [notes, setNotes] = useState('');
  // Added costPrice: 0 to match OrderItem interface
  const [items, setItems] = useState<OrderItem[]>([
    { id: Math.random().toString(36).substr(2, 9), productId: 'AD-HOC', name: '', quantity: 1, unitPrice: 0, costPrice: 0 }
  ]);

  // Added costPrice: 0 to match OrderItem interface when adding a new item
  const addItem = () => {
    setItems([...items, { id: Math.random().toString(36).substr(2, 9), productId: 'AD-HOC', name: '', quantity: 1, unitPrice: 0, costPrice: 0 }]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(items.filter(item => item.id !== id));
    }
  };

  const updateItem = (id: string, field: keyof OrderItem, value: any) => {
    setItems(items.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const calculateTotal = () => {
    return items.reduce((sum, item) => sum + (item.quantity * item.unitPrice), 0);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const total = calculateTotal();

    // Fixed: Added missing 'payments' property for the Order interface
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      invoiceNumber: `INV-${Date.now().toString().slice(-6)}`,
      customerId: 'AD-HOC',
      customerName,
      customerEmail,
      customerType: LocationType.JAKARTA,
      customerAddress,
      orderDate: new Date().toISOString(),
      status: OrderStatus.PENDING,
      items,
      subtotal: total,
      downPayment: 0,
      payments: [],
      total: total,
      notes
    };

    onSubmit(newOrder);
  };

  return (
    <div className="bg-white rounded-2xl shadow-xl shadow-gray-200 border border-gray-100 p-8">
      <h2 className="text-2xl font-bold text-gray-900 mb-8">Form Pesanan Baru</h2>

      <form onSubmit={handleSubmit} className="space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Nama Pelanggan</label>
            <input 
              required
              type="text" 
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="Contoh: Budi Santoso"
              value={customerName}
              onChange={(e) => setCustomerName(e.target.value)}
            />
          </div>
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Email Pelanggan</label>
            <input 
              required
              type="email" 
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
              placeholder="budi@email.com"
              value={customerEmail}
              onChange={(e) => setCustomerEmail(e.target.value)}
            />
          </div>
          <div className="md:col-span-2 space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Alamat Pengiriman</label>
            <textarea 
              required
              rows={3}
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
              placeholder="Jl. Merdeka No. 123, Jakarta"
              value={customerAddress}
              onChange={(e) => setCustomerAddress(e.target.value)}
            />
          </div>
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <h3 className="text-lg font-bold text-gray-900">Daftar Barang</h3>
            <button 
              type="button"
              onClick={addItem}
              className="flex items-center gap-1 text-sm text-indigo-600 hover:text-indigo-700 font-semibold"
            >
              <Plus className="w-4 h-4" />
              Tambah Item
            </button>
          </div>

          <div className="space-y-3">
            {items.map((item, index) => (
              <div key={item.id} className="grid grid-cols-12 gap-3 items-end bg-gray-50 p-4 rounded-xl border border-gray-200">
                <div className="col-span-12 md:col-span-6 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Nama Barang</label>
                  <input 
                    required
                    type="text"
                    placeholder="Nama Barang"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.name}
                    onChange={(e) => updateItem(item.id, 'name', e.target.value)}
                  />
                </div>
                <div className="col-span-4 md:col-span-2 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Qty</label>
                  <input 
                    required
                    type="number"
                    min="1"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.quantity}
                    onChange={(e) => updateItem(item.id, 'quantity', parseInt(e.target.value) || 0)}
                  />
                </div>
                <div className="col-span-5 md:col-span-3 space-y-1">
                  <label className="text-[10px] uppercase font-bold text-gray-400">Harga Satuan</label>
                  <input 
                    required
                    type="number"
                    min="0"
                    className="w-full px-3 py-2 rounded-md border border-gray-200 text-sm focus:ring-1 focus:ring-indigo-500 outline-none"
                    value={item.unitPrice}
                    onChange={(e) => updateItem(item.id, 'unitPrice', parseInt(e.target.value) || 0)}
                  />
                </div>
                <div className="col-span-3 md:col-span-1 flex justify-center pb-2">
                  <button 
                    type="button"
                    onClick={() => removeItem(item.id)}
                    className="text-red-400 hover:text-red-600 transition-colors"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="space-y-2">
            <label className="block text-sm font-semibold text-gray-700">Catatan (Opsional)</label>
            <textarea 
              rows={2}
              className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all resize-none"
              placeholder="Catatan tambahan untuk pesanan ini..."
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
            />
          </div>

        <div className="pt-6 border-t border-gray-100 flex items-center justify-between">
          <div className="text-gray-500">
            Total Pembayaran: <span className="text-2xl font-bold text-gray-900">Rp {calculateTotal().toLocaleString()}</span>
          </div>
          <button 
            type="submit"
            className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-xl font-bold transition-all shadow-lg shadow-indigo-100"
          >
            <Save className="w-5 h-5" />
            Simpan Pesanan
          </button>
        </div>
      </form>
    </div>
  );
};

export default OrderForm;

