import React, { useRef, useState, useEffect } from 'react';
// Removed redundant global JSX declaration to fix duplicate index signature error.
import { Download, Share2, Sparkles, Image as ImageIcon, FileText, Loader2 } from 'lucide-react';
import { Order } from '../types';
import { getSmartOrderSummary } from '../services/geminiService';
import html2canvas from 'html2canvas';
import { jsPDF } from 'jsPDF';

interface InvoiceViewProps {
  order: Order;
  onNotify?: (msg: string, type: 'success' | 'info') => void;
}

const InvoiceView: React.FC<InvoiceViewProps> = ({ order, onNotify }) => {
  const invoiceRef = useRef<HTMLDivElement>(null);
  const [aiSummary, setAiSummary] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  useEffect(() => {
    // Start AI fetch without blocking component render
    const fetchSummary = async () => {
      setIsAiLoading(true);
      try {
        const summary = await getSmartOrderSummary(order);
        setAiSummary(summary);
      } catch (e) {
        setAiSummary("Ringkasan tidak tersedia.");
      } finally {
        setIsAiLoading(false);
      }
    };

    setAiSummary(''); // Reset for new order
    fetchSummary();
  }, [order.id]); // Only refetch if order ID changes

  const handleDownloadJPG = async () => {
    if (!invoiceRef.current) return;
    try {
      if (onNotify) onNotify("Menyiapkan Gambar...", "info");
      const canvas = await html2canvas(invoiceRef.current, { 
        scale: 2,
        useCORS: true,
        logging: false
      });
      const link = document.createElement('a');
      link.download = `NOTA-${order.invoiceNumber}.jpg`;
      link.href = canvas.toDataURL('image/jpeg', 0.9);
      link.click();
      if (onNotify) onNotify("Berhasil simpan JPG", "success");
    } catch (e) {
      if (onNotify) onNotify("Gagal ekspor gambar", "info");
    }
  };

  const handleDownloadPDF = async () => {
    if (!invoiceRef.current) return;
    try {
      if (onNotify) onNotify("Membuat PDF...", "info");
      const canvas = await html2canvas(invoiceRef.current, { 
        scale: 2, 
        useCORS: true,
        logging: false
      });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (canvas.height * pdfWidth) / canvas.width;
      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`NOTA-${order.invoiceNumber}.pdf`);
      if (onNotify) onNotify("Berhasil simpan PDF", "success");
    } catch (e) {
      if (onNotify) onNotify("Gagal ekspor PDF", "info");
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
      <div className="lg:col-span-2 space-y-6">
        <div className="flex items-center justify-between bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
