          <div className="space-y-1">
            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Alamat Lengkap</label>
            <input className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-indigo-500 outline-none" value={formData.address} onChange={e => setFormData({...formData, address: e.target.value})} />
